        path.pop();
    }
}

function solve() {
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout
    });
    let n, nums;
    rl.on('line', line => {
        if (n === undefined) {
            n = parseInt(line);
        } else {
            nums = line.split(' ').map(Number).sort((a, b) => a - b);
            let subsets = [];
            backtrack(0, [], nums, subsets);
            for (let subset of subsets) {
                console.log(subset.join(' '));
            }
            rl.close();
        }
    });
}
solve();

