	sort(nums.begin(), nums.end());
	function<void(int, vector<int>)> backtrack = [&](int start, vector<int> path){
		if(!path.empty()){
			for(int x: path) cout << x << ' ';
			cout << '\n';
		}
		for(int i = start; i < n; i++){
			if(i > start && nums[i] == nums[i - 1]) continue;
			path.push_back(nums[i]);
			backtrack(i + 1, path);
			path.pop_back();
		}
	};
	backtrack(0, {});
	cout << '\n';
}
